from flask import Flask, session, redirect, url_for, request
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

# Authorization server URL and client ID
AUTH_SERVER_URL = 'https://example.com/oauth/authorize'
CLIENT_ID = 'your_client_id_here'

# Redirect URI for authorization code
REDIRECT_URI = url_for('callback', _external=True)

@app.route('/login')
def login():
    # Generate a random state to prevent CSRF attacks
    state = request.sid

    # Authorization URL with client ID, redirect URI, and state
    auth_url = f'{AUTH_SERVER_URL}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&response_type=code&state={state}'

    return redirect(auth_url)

@app.route('/callback')
def callback():
    # Get the authorization code from the request query string
    code = request.args.get('code')

    if not code:
        return 'Invalid authorization code', 400

    # Exchange the authorization code for an access token using requests.post()
    auth_token_url = 'https://example.com/oauth/token'
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI
    }

    response = requests.post(auth_token_url, headers=headers, data=data)

    if response.status_code == 200:
        # Store the access token in the session
        session['access_token'] = response.json()['access_token']
        return redirect(url_for('protected'))
    else:
        return 'Failed to obtain access token', 400

if __name__ == '__main__':
    app.run(debug=True)